import React from 'react';

export const getStatusLabel = (status) => {
  switch (status) {
    case 'PENDING': return 'Chờ xử lý';
    case 'ASSIGNED': return 'Đã phân công';
    case 'IN_PROGRESS': return 'Đang hỗ trợ';
    case 'RESOLVED': return 'Đã hoàn thành';
    case 'CANCELLED': return 'Đã hủy';
    default: return status;
  }
};

export const getStatusStyle = (status) => {
  switch (status) {
    case 'PENDING': return { background: '#FEF3C7', color: '#B45309' };
    case 'ASSIGNED': return { background: '#DBEAFE', color: '#1D4ED8' };
    case 'IN_PROGRESS': return { background: '#E0F2FE', color: '#0369A1' };
    case 'RESOLVED': return { background: '#DCFCE7', color: '#15803D' };
    case 'CANCELLED': return { background: '#FEE2E2', color: '#B91C1C' };
    default: return { background: '#E2E8F0', color: '#475569' };
  }
};

export const StatusBadge = ({ status }) => (
  <span style={{
    ...getStatusStyle(status),
    padding: '8px 14px',
    borderRadius: '999px',
    fontSize: '0.85rem',
    fontWeight: '700'
  }}>
    {getStatusLabel(status)}
  </span>
);
